<template><view class="page"><view class="intro"><text class="eyebrow">MEMBERSHIP</text><text class="title">选择适合你的方案</text><text class="desc">当前为模拟支付流程，不会产生真实扣款。</text></view><view v-for="plan in plans" :key="plan.id" :class="['plan',plan.id==='pro'?'featured':'']"><view class="head"><view><text class="tag">{{plan.tag}}</text><text class="name">{{plan.name}}</text></view><view><text class="currency">¥</text><text class="price">{{plan.price}}</text></view></view><text class="description">{{plan.description}}</text><view class="benefit">✓ {{plan.quota}} 次生成额度</view><button :loading="buying===plan.id" @click="buy(plan)">模拟购买</button></view><view class="orders"><text class="section-title">最近订单</text><view v-if="!orders.length" class="empty">暂无订单</view><view v-for="item in orders" :key="item.id" class="order"><view><text>{{item.product_name}}</text><text>{{formatDate(item.created_at)}} · {{item.order_no}}</text></view><view><text>¥{{item.amount}}</text><text class="paid">已支付</text></view></view></view></view></template>
<script setup>import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import{plans,getOrders,mockPurchase}from'@/services/phase3Mock.js';const orders=ref([]);const buying=ref('');onShow(()=>orders.value=getOrders());const buy=plan=>uni.showModal({title:`购买${plan.name}`,content:`模拟支付 ¥${plan.price}，不会真实扣款。`,confirmText:'确认支付',success:({confirm})=>{if(!confirm)return;buying.value=plan.id;setTimeout(()=>{mockPurchase(plan);orders.value=getOrders();buying.value='';uni.showToast({title:'权益已到账',icon:'success'});},600);}});const formatDate=v=>String(v||'').replace('T',' ').slice(0,16);</script>
<style scoped>.page{min-height:100vh;padding:36rpx 30rpx 90rpx;box-sizing:border-box;color:#292620;background:#f7f4ee}.eyebrow,.title,.desc{display:block}.eyebrow{color:#8a6f42;font-size:17rpx;letter-spacing:4rpx}.title{margin-top:10rpx;font-family:serif;font-size:43rpx;font-weight:700}.desc{margin-top:10rpx;color:#948a7d;font-size:21rpx}.plan{margin-top:22rpx;padding:28rpx;border:1rpx solid transparent;border-radius:22rpx;background:#fff}.plan.featured{border-color:#b38a55;box-shadow:0 10rpx 28rpx rgba(149,105,53,.12)}.head,.order{display:flex;justify-content:space-between}.tag,.name,.description,.benefit,.order text{display:block}.tag{color:#9b6a2b;font-size:18rpx}.name{margin-top:6rpx;font-size:30rpx;font-weight:700}.currency{font-size:20rpx}.price{font-size:43rpx;font-weight:700}.description{margin-top:18rpx;color:#81786d;font-size:21rpx;line-height:1.6}.benefit{margin-top:16rpx;color:#476456;font-size:21rpx}.plan button{margin-top:22rpx;color:#fff;background:#3d594c}.orders{margin-top:38rpx}.section-title{font-size:30rpx;font-weight:700}.empty{margin-top:18rpx;padding:35rpx;color:#9a9185;text-align:center;border-radius:18rpx;background:#fff}.order{margin-top:14rpx;padding:22rpx;border-radius:17rpx;background:#fff}.order text:first-child{font-size:23rpx;font-weight:700}.order text:last-child{margin-top:6rpx;color:#9a9186;font-size:18rpx}.order>view:last-child{text-align:right}.order .paid{color:#3f7559}</style>
